+fn canonical_digest_f64(value: f64) -> f64 {
+    if value.is_finite() { value } else { 0.0 }
+}
+
+fn push_length_prefixed_str(hasher: &mut Sha256, value: &str) {
+    hasher.update((value.len() as u64).to_le_bytes());
+    hasher.update(value.as_bytes());
+}
